// home.spec.json — the parent. Owns layoutFile, customTypes, and the
// sub-spec roster. Every field here is inherited by the children.
{
  "type":    "screen_parent_spec",
  "version": "1.0",
  "metadata": {
    "name":        "Home",
    "displayName": "Home",
    "description": "Home dashboard (feed + notifications + recent activity).",
    "platforms":   ["ios", "android", "web"],
    "layoutFile":  "home"                     // shared visual tree
  },
  "structure":   { "components": [], "layout": {} },
  "dataFlow":    {
    "customTypes": [                             // shared across all subs
      { "name": "FeedRow", "properties": [ /* … */ ] }
    ]
  },
  "subSpecs": [                                  // every child listed here
    { "file": "home/feed.spec.json",          "name": "HomeFeed" },
    { "file": "home/notifications.spec.json", "name": "HomeNotifications" },
    { "file": "home/recent.spec.json",        "name": "HomeRecent" }
  ]
}

// home/feed.spec.json — one sub. Only declares state + handlers for its
// own region; layoutFile and customTypes are inherited via parentSpec.
{
  "type":    "screen_sub_spec",
  "version": "1.0",
  "metadata": {
    "name":        "HomeFeed",
    "description": "Feed region — posts Collection + refresh button.",
    "parentSpec":  "../home.spec.json"         // relative to this file
  },
  "stateManagement": {
    "uiVariables": [
      { "name": "feedRows",    "type": "[FeedRow]", "initial": "[]" },
      { "name": "isRefreshing", "type": "Bool",     "initial": "false" }
    ],
    "eventHandlers": [
      { "name": "onRefreshFeed" },
      { "name": "onSelectPost", "params": [{ "name": "id", "type": "String" }] }
    ]
  }
}

// What `jui build` does with a parent + sub group:
//
// 1. Read home.spec.json      → discover subSpecs[] roster
// 2. For each sub:
//      a. Read sub spec         → validate against screen_sub_spec schema
//      b. Resolve parentSpec    → inherit layoutFile + customTypes + platforms
//      c. Merge into a virtual full-screen spec (parent's structure + sub's state)
//      d. Run layout_importer on the merged spec (see /spec/layout-file)
//      e. Generate per-platform VM class named after metadata.name (HomeFeed, …)
// 3. Generate one <ScreenName>.tsx / .swift / .kt per sub — same Layout file,
//    different ViewModel class bound in.
//
// The parent itself does not produce a standalone VM — it's a composition spec.
// Apps render the screen by mounting the parent's Layout and deciding which
// sub's ViewModel to bind per region (parent-driven composition).
